```bash
python3 - <<'PY'
import re, subprocess
path="llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp"
s=open(path).read()
old = """  // select Cond, !X, X -> xor Cond, X
  // Guard to avoid changing poison semantics: require RHS (X) to be safe-to-speculatively-execute.
  if (CondVal->getType() == SI.getType() && isKnownInversion(FalseVal, TrueVal)) {
    if (isSafeToSpeculativelyExecute(FalseVal))
      return BinaryOperator::CreateXor(CondVal, FalseVal);
  }
"""
new = """  // select Cond, !X, X -> xor Cond, X
  // Guard to avoid changing poison semantics: require RHS (X) to be safe-to-speculatively-execute.
  if (CondVal->getType() == SI.getType() && isKnownInversion(FalseVal, TrueVal)) {
    if (isa<Constant>(FalseVal))
      return BinaryOperator::CreateXor(CondVal, FalseVal);
    if (auto *XI = dyn_cast<Instruction>(FalseVal)) {
      SimplifyQuery Q = SQ.getWithInstruction(&SI);
      if (isSafeToSpeculativelyExecute(XI, &SI, Q.AC, Q.DT, &TLI, /*InSpeculation=*/false))
        return BinaryOperator::CreateXor(CondVal, FalseVal);
    }
  }
"""
if old in s:
    s=s.replace(old,new)
else:
    # Fallback: replace the non-guarded original block by injecting guarded logic
    s=s.replace(
        "  // select Cond, !X, X -> xor Cond, X\n  if (CondVal->getType() == SI.getType() && isKnownInversion(FalseVal, TrueVal))\n    return BinaryOperator::CreateXor(CondVal, FalseVal);\n",
        new
    )
open(path,"w").write(s)
print("Updated guard to use Instruction* overload with analysis context.")
# Show context
out = subprocess.check_output(["nl","-ba",path]).decode().splitlines()
for i,l in enumerate(out):
    if "select Cond, !X, X -> xor Cond, X" in l:
        print("\n".join(out[max(0,i-3):min(len(out),i+14)]))
        break
