import sys, subprocess
path="llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp"
s=open(path).read()
target = """      unsigned Code = IsAnd ? getICmpCode(PredL) & getICmpCode(PredR)
                              : getICmpCode(PredL) | getICmpCode(PredR);
